127	long long BASE_WEIGHT = 100000; 
128	
129	double estimate_log2(double val) {
130	    if (val <= 1.0) return 0.0;
131	    return std::log2(val);
132	}
133	
134	int calculate_estimated_query_cost(int N_val, int k_pivots_val) {
135	    if (k_pivots_val <= 0) return 0;
136	    if (k_pivots_val == 1) {
137	        return (N_val > 1) ? (N_val - 1) : 0;
138	    }
139	
140	    double cost = 0;
141	    cost += static_cast<double>(k_pivots_val) * estimate_log2(static_cast<double>(k_pivots_val)); 
142	    for (int j = 2; j < k_pivots_val; ++j) { 
143	        if (j-1 > 0) cost += estimate_log2(static_cast<double>(j - 1)); 
144	    }
145	    cost += static_cast<double>(N_val - k_pivots_val) * estimate_log2(static_cast<double>(k_pivots_val)); 
146	    return static_cast<int>(std::ceil(cost));
147	}
