            double new_sum_sq_group_totals_cand = current_sum_sq_group_totals;
            new_sum_sq_group_totals_cand -= static_cast<double>(old_sum_grp_A)*old_sum_grp_A + static_cast<double>(old_sum_grp_B)*old_sum_grp_B;
