                int back1_of_G1 = group_items_indices[grp1_idx].back();
                if (item1_original_idx != back1_of_G1) {
                    group_items_indices[grp1_idx][pos1_in_G1] = back1_of_G1;
                    item_pos_in_group_vector[back1_of_G1] = pos1_in_G1;
                }
