std::chrono::steady_clock::time_point program_start_time;
std::chrono::milliseconds time_limit_ms(1850);

int N, D, Q;
int queries_made = 0;
std::mt19937 rng_engine;

char perform_query(const std::vector<int>& L, const std::vector<int>& R) {
    queries_made++;
    std::cout << L.size() << " " << R.size();
    for (int x : L) std::cout << " " << x;
    for (int x : R) std::cout << " " << x;
    std::cout << std::endl;
    char result;
    std::cin >> result;
    return result;
}

std::map<std::pair<int,int>, char> cmp_cache;

char compare_items(int a, int b) {
    if (a == b) return '=';
    auto key = std::make_pair(std::min(a,b), std::max(a,b));
    auto it = cmp_cache.find(key);
    if (it != cmp_cache.end()) {
        char c = it->second;
        if (a == key.first) return c;
        return c == '<' ? '>' : (c == '>' ? '<' : '=');
    }
    if (queries_made >= Q) return '=';
    char res = perform_query({a}, {b});
    char stored = (a < b) ? res : (res == '<' ? '>' : (res == '>' ? '<' : '='));
    cmp_cache[key] = stored;
    return res;
}

void merge_sort_impl(std::vector<int>& arr, int l, int r) {
    if (l >= r) return;
    int m = l + (r - l) / 2;
    merge_sort_impl(arr, l, m);
    merge_sort_impl(arr, m + 1, r);
    std::vector<int> tmp;
    int i = l, j = m + 1;
    while (i <= m && j <= r) {
        if (queries_made >= Q) {
            while (i <= m) tmp.push_back(arr[i++]);
            while (j <= r) tmp.push_back(arr[j++]);
            break;
        }
        char c = compare_items(arr[i], arr[j]);
        if (c == '<' || c == '=') tmp.push_back(arr[i++]);
        else tmp.push_back(arr[j++]);
    }
    while (i <= m) tmp.push_back(arr[i++]);
    while (j <= r) tmp.push_back(arr[j++]);
    for (int x = l; x <= r; x++) arr[x] = tmp[x - l];
}

int main() {
    std::ios_base::sync_with_stdio(false);
