    rng_engine.seed(std::chrono::duration_cast<std::chrono::nanoseconds>(
        std::chrono::steady_clock::now().time_since_epoch()).count());

    std::cin >> N >> D >> Q;

    // Phase 1: Sort items using merge sort
    // Budget: use up to 70% of queries for sorting, rest for refinement
    int sort_budget = (int)(Q * 0.70);
    int refine_budget = Q - sort_budget;

    std::vector<int> sorted_items(N);
    std::iota(sorted_items.begin(), sorted_items.end(), 0);

