    char stored = (a < b) ? res : (res == '<' ? '>' : (res == '>' ? '<' : '='));
    cache[key] = stored;
    return res;
}

void msort(std::vector<int>& arr, int l, int r) {
    if (l >= r) return;
    int m = (l + r) / 2;
    msort(arr, l, m);
    msort(arr, m + 1, r);
    std::vector<int> tmp;
    int i = l, j = m + 1;
    while (i <= m && j <= r) {
        if (queries_used >= Q) {
            while (i <= m) tmp.push_back(arr[i++]);
            while (j <= r) tmp.push_back(arr[j++]);
            break;
        }
        char c = compare(arr[i], arr[j]);
        if (c == '<' || c == '=') tmp.push_back(arr[i++]);
        else tmp.push_back(arr[j++]);
    }
    while (i <= m) tmp.push_back(arr[i++]);
    while (j <= r) tmp.push_back(arr[j++]);
    for (int x = l; x <= r; x++) arr[x] = tmp[x - l];
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    start_time = std::chrono::steady_clock::now();
    rng.seed(std::chrono::duration_cast<std::chrono::nanoseconds>(
        std::chrono::steady_clock::now().time_since_epoch()).count());

    std::cin >> N >> D >> Q;

    // Phase 1: Sort all items
    std::vector<int> sorted_items(N);
    std::iota(sorted_items.begin(), sorted_items.end(), 0);
    msort(sorted_items, 0, N - 1);

    // Phase 2: Assign weights using exponential order statistics
    // E[X_(k:N)] for Exp(lambda) = (1/lambda) * sum_{j=1}^{k} 1/(N-j+1)
    // lambda = 1e-5, so 1/lambda = 1e5
    // Weights are max(1, round(w')), with w' truncated at 1e5*N/D
    // Use the exact order statistic formula (not quantile approximation)
    double inv_lambda = 1e5;
    std::vector<double> weights(N);
    double cumH = 0.0;
    for (int k = 0; k < N; k++) {
        cumH += 1.0 / (N - k);
        weights[sorted_items[k]] = std::max(1.0, inv_lambda * cumH);
    }

    // Phase 3: Greedy partition (LPT - Longest Processing Time first)
    std::vector<int> assignment(N, 0);
    std::vector<double> group_sums(D, 0.0);

    std::vector<int> items_desc(N);
    std::iota(items_desc.begin(), items_desc.end(), 0);
    std::sort(items_desc.begin(), items_desc.end(), [&](int a, int b) {
        return weights[a] > weights[b];
    });

    for (int idx : items_desc) {
        int best_g = 0;
        for (int g = 1; g < D; g++) {
            if (group_sums[g] < group_sums[best_g]) best_g = g;
        }
        assignment[idx] = best_g;
        group_sums[best_g] += weights[idx];
    }

    // Phase 4: SA optimization
    double total_sum = 0;
    for (int i = 0; i < N; i++) total_sum += weights[i];
    double mean = total_sum / D;
    double sum_sq = 0;
    for (double s : group_sums) sum_sq += s * s;
    double variance = sum_sq / D - mean * mean;

    double T = std::max(1.0, std::sqrt(variance) * 0.5);
    std::uniform_real_distribution<double> unif(0.0, 1.0);
    std::uniform_int_distribution<int> item_dist(0, N - 1);
    std::uniform_int_distribution<int> grp_dist(0, D - 1);
    double cool = 0.99998;
    int iter = 0;

    while (true) {
        iter++;
        if (iter % 512 == 0) {
            auto now = std::chrono::steady_clock::now();
            if (std::chrono::duration_cast<std::chrono::milliseconds>(now - start_time).count() >= 1850)
                break;
            T *= cool;
        }
        if (T < 1e-15) break;

        if (rng() % 3 == 0) {
            int item1 = item_dist(rng);
            int item2 = item_dist(rng);
            if (assignment[item1] == assignment[item2]) continue;
            int g1 = assignment[item1], g2 = assignment[item2];
            double w1 = weights[item1], w2 = weights[item2];
            double ns1 = group_sums[g1] - w1 + w2;
            double ns2 = group_sums[g2] - w2 + w1;
            double new_sum_sq = sum_sq - group_sums[g1]*group_sums[g1] - group_sums[g2]*group_sums[g2] + ns1*ns1 + ns2*ns2;
            double new_var = new_sum_sq / D - mean * mean;
            double delta = new_var - variance;
            if (delta < 0 || unif(rng) < std::exp(-delta / T)) {
                variance = new_var; sum_sq = new_sum_sq;
                group_sums[g1] = ns1; group_sums[g2] = ns2;
                assignment[item1] = g2; assignment[item2] = g1;
            }
        } else {
            int item = item_dist(rng);
            int old_g = assignment[item];
            int new_g = grp_dist(rng);
            if (new_g == old_g) continue;
            double w = weights[item];
            double ns_old = group_sums[old_g] - w;
            double ns_new = group_sums[new_g] + w;
            double new_sum_sq = sum_sq - group_sums[old_g]*group_sums[old_g] - group_sums[new_g]*group_sums[new_g] + ns_old*ns_old + ns_new*ns_new;
            double new_var = new_sum_sq / D - mean * mean;
            double delta = new_var - variance;
            if (delta < 0 || unif(rng) < std::exp(-delta / T)) {
                variance = new_var; sum_sq = new_sum_sq;
                group_sums[old_g] = ns_old; group_sums[new_g] = ns_new;
                assignment[item] = new_g;
            }
        }
    }

    // Exhaust remaining queries
    while (queries_used < Q) {
        do_query({0}, {1});
    }

    for (int i = 0; i < N; i++) {
        std::cout << assignment[i] << (i == N - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}
